// src/App.js
import React, { useState } from "react";
import UploadForm from "./components/UploadForm";
import ResultView from "./components/ResultView";

export default function App() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  return (
    <div style={{
      minHeight: "100vh",
      background: "#eef2ff",
      padding: "40px 20px",
      display: "flex",
      justifyContent: "center",
      alignItems: "flex-start"
    }}>
      <div style={{
        width: "100%",
        maxWidth: "850px",
        background: "white",
        borderRadius: "14px",
        padding: "35px",
        boxShadow: "0 6px 22px rgba(0,0,0,0.1)"
      }}>
        <h1 style={{
          textAlign: "center",
          color: "#1e40af",
          fontSize: "36px",
          marginBottom: "25px",
          fontWeight: "700"
        }}>
          Scan2Learn
        </h1>

        <UploadForm setResult={setResult} setLoading={setLoading} />

        {loading && (
          <p style={{ textAlign: "center", marginTop: "15px", fontSize: "18px" }}>
            Processing image…
          </p>
        )}

        {result && <ResultView data={result} />}
      </div>
    </div>
  );
}
